import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Home, Menu, X } from 'lucide-react';

export default function Navbar() {
  const [isOpen, setIsOpen] = useState(false);

  const toggleMenu = () => {
    setIsOpen(!isOpen);
  };

  return (
    <nav className="bg-indigo-600 text-zinc-200 shadow-2xl sticky top-0 z-50">
      <div className="container mx-auto flex justify-between items-center py-4 md:py-6">
        <Link to="/" className="text-2xl font-bold font-inter">LuxuryStay</Link>
        <button className="md:hidden" onClick={toggleMenu}>
          {isOpen ? <X size={24} className="text-zinc-200" /> : <Menu size={24} className="text-zinc-200" />}
        </button>
        <ul className={`md:flex items-center ${isOpen ? 'block' : 'hidden'} md:space-x-8`}>
          <li>
            <Link to="/" className="text-zinc-200 hover:text-indigo-400 transition duration-200">Home</Link>
          </li>
          <li>
            <Link to="/about" className="text-zinc-200 hover:text-indigo-400 transition duration-200">About</Link>
          </li>
          <li>
            <Link to="/contact" className="text-zinc-200 hover:text-indigo-400 transition duration-200">Contact</Link>
          </li>
        </ul>
      </div>
    </nav>
  );
}

