            <p className="text-gray-200">Experience the best of luxury living with our top-notch amenities and services.</p>
          </div>
          <button
            className={`block w-full px-4 py-2 text-sm font-medium text-white bg-indigo-600 rounded-md shadow hover:bg-indigo-700 transition duration-200 ${tabIndex === 1 ? 'bg-indigo-600' : 'bg-gray-800'}`}
            onClick={() => handleTabClick(1)}
          >
            Learn More
          </button>
        </div>
        <div className={`rounded-xl bg-indigo-600 shadow-md hover:bg-indigo-700 transition duration-200 ${tabIndex === 2 ? 'border border-indigo-600' : 'border border-gray-800'}`}>
